import { diag, DiagConsoleLogger, DiagLogLevel, trace } from "@opentelemetry/api";
import { NodeTracerProvider } from "@opentelemetry/sdk-trace-node";
import { SimpleSpanProcessor } from "@opentelemetry/sdk-trace-base";
import { OTLPTraceExporter } from "@opentelemetry/exporter-trace-otlp-proto";

diag.setLogger(new DiagConsoleLogger(), DiagLogLevel.ERROR);

const region = process.env.ARIZE_REGION ?? "ca-central-1a";
const url = `https://otlp.${region}.arize.com/v1/traces`;
const exporter = new OTLPTraceExporter({
  url,
  headers: {
    "arize-space-id": process.env.ARIZE_SPACE_ID,
    "arize-api-key": process.env.TEST_KEY,
  },
});

const provider = new NodeTracerProvider({ spanProcessors: [new SimpleSpanProcessor(exporter)] });
provider.register();

const span = trace.getTracer("twyne-otlp-probe").startSpan("twyne.otlp.auth-probe");
span.setAttribute("openinference.span.kind", "LLM");
span.setAttribute("llm.model_name", "probe");
span.end();

const res = await exporter
  .forceFlush?.()
  .then(() => "forceFlush ok")
  .catch((e) => `forceFlush err: ${e}`);
await provider.forceFlush();
console.log(`[probe] url=${url} ${res ?? ""}`);
await provider.shutdown();
console.log("[probe] done (no export error above = accepted)");

