// Reproduce the EXACT Bifrost provider wiring from convex/agents.ts
import { createOpenAI } from "@ai-sdk/openai";
import { generateText } from "ai";

const bifrostUrl = process.env.BIFROST_BASE_URL;
const bifrostKey = process.env.BIFROST_API_KEY;
const modelId = process.env.BIFROST_DEFAULT_MODEL ?? "neuralwatt/qwen3.5-397b-fast";

const bifrost = createOpenAI({
  baseURL: bifrostUrl.replace(/\/$/, ""),
  apiKey: "bifrost-dummy",
  headers: bifrostKey ? { "x-bifrost-api-key": bifrostKey } : undefined,
});

try {
  const { text } = await generateText({
    model: bifrost.chat(modelId),
    prompt: "say OK",
    maxOutputTokens: 5,
  });
  console.log("AI SDK path OK ->", JSON.stringify(text));
} catch (e) {
  console.log("AI SDK path FAILED ->", e?.message ?? e);
  if (e?.responseBody) console.log("body:", String(e.responseBody).slice(0, 300));
}

