    model: bifrost.chat(modelId),
    prompt: "say OK",
    maxOutputTokens: 5,
  });
  console.log("FIXED path OK ->", JSON.stringify(text));
} catch (e) {
  console.log("FIXED path FAILED ->", e?.message ?? e);
  if (e?.responseBody) console.log("body:", String(e.responseBody).slice(0, 300));
}

