1	/**
2	 * LLM-as-judge scorer for Twyne's persona feedback experiments.
3	 *
4	 * Reads the generations produced by `evals/run-experiment.ts` (`evals/runs.json`)
5	 * and the matching `evals/dataset.jsonl`, then applies two rubrics through the
6	 * Bifrost gateway:
7	 *
8	 *   - faithfulness-to-draft : does the feedback engage THIS draft (grounded=1)
9	 *                             or is it generic boilerplate (generic=0)?
10	 *   - feedback-helpfulness  : is the feedback useful + on-persona (good=1) or
11	 *                             vague/off-topic (poor=0)?
12	 *
13	 * These mirror, verbatim, the two Arize template evaluators created under the
14	 * "kmannoel Space" (faithfulness-to-draft / feedback-helpfulness). The Arize
15	 * native judge task is blocked by the AI-integration's bearer injection (it
16	 * sends `Authorization: Bearer` to Bifrost → 401); this script runs the same
17	 * rubrics with header-only auth so the eval loop is reproducible in-repo and in
18	 * CI without that integration. Writes `evals/scores.json`.
19	 *
20	 * Usage:
21	 *   BIFROST_BASE_URL=https://... BIFROST_API_KEY=sk_bf_xxx \
22	 *     JUDGE_MODEL=neuralwatt/kimi-k2.6 bun run eval:judge
23	 *
24	 * Read-only w.r.t. the repo otherwise: only writes `evals/scores.json`.
25	 */
26	import { readFileSync, writeFileSync } from "node:fs";
27	import { dirname, resolve } from "node:path";
28	import { fileURLToPath } from "node:url";
29	
30	const HERE = dirname(fileURLToPath(import.meta.url));
31	const DATASET_PATH = resolve(HERE, "dataset.jsonl");
32	const RUNS_PATH = resolve(HERE, "runs.json");
33	const SCORES_PATH = resolve(HERE, "scores.json");
34	
35	const BIFROST_BASE_URL = process.env.BIFROST_BASE_URL;
36	const BIFROST_API_KEY = process.env.BIFROST_API_KEY;
37	const JUDGE_MODEL = process.env.JUDGE_MODEL ?? "neuralwatt/kimi-k2.6";
38	
39	interface DatasetRow {
40	  case_id: string;
41	  persona: string;
42	  instruction: string;
43	  draftText: string;
44	}
45	interface RunOutput {
46	  case_id: string;
47	  output: string;
48	}
49	interface Verdict {
50	  label: string;
51	  score: number | null;
52	  explanation: string;
53	}
54	interface CaseScore {
55	  case_id: string;
56	  persona: string;
57	  faithfulness: Verdict;
58	  helpfulness: Verdict;
59	}
60	
61	const FAITHFULNESS_TEMPLATE = (draft: string, output: string): string =>
62	  `You judge whether an AI editor's feedback genuinely engages with the SPECIFIC ` +
63	  `draft it was given, versus generic writing advice that could apply to any text.\n\n` +
64	  `Draft:\n${draft}\n\nEditor feedback:\n${output}\n\n` +
65	  `Answer "grounded" if the feedback references specific content, claims, or wording ` +
66	  `from THIS draft. Answer "generic" if it is boilerplate advice that could apply to any text.`;
67	
68	const HELPFULNESS_TEMPLATE = (
69	  persona: string,
70	  draft: string,
71	  output: string,
72	): string =>
73	  `You evaluate an AI editor persona's feedback for quality.\n\n` +
74	  `Persona role: ${persona}\nDraft:\n${draft}\n\nFeedback:\n${output}\n\n` +
75	  `Is the feedback helpful, specific, and consistent with the persona's role and the draft? ` +
76	  `Answer "good" if it is useful and on-task, "poor" if it is vague, off-topic, or unhelpful.`;
77	
78	const CHOICES: Record<string, Record<string, number>> = {
79	  faithfulness: { grounded: 1, generic: 0 },
80	  helpfulness: { good: 1, poor: 0 },
81	};
82	
83	async function judge(
84	  prompt: string,
85	  valid: Record<string, number>,
86	  signal: AbortSignal,
87	): Promise<Verdict> {
88	  if (!BIFROST_BASE_URL) throw new Error("BIFROST_BASE_URL is required");
89	  const labels = Object.keys(valid);
90	  const system =
91	    `You are a strict evaluator. Read the rubric, then respond with a JSON object ` +
92	    `exactly: {"label": "<one of: ${labels.join(", ")}>", "explanation": "<one sentence>"}. ` +
93	    `No other text.`;
94	  const res = await fetch(
95	    `${BIFROST_BASE_URL.replace(/\/$/, "")}/chat/completions`,
96	    {
97	      method: "POST",
98	      // Header-only auth: Bifrost passes its stored provider key through. A
99	      // bearer token would be misread as a virtual-key lookup → 401. This is
100	      // exactly why the Arize integration's auth_type must be proxy_with_headers.
101	      headers: {
102	        "content-type": "application/json",
103	        "x-bifrost-api-key": BIFROST_API_KEY ?? "",
104	      },
105	      body: JSON.stringify({
106	        model: JUDGE_MODEL,
107	        messages: [
108	          { role: "system", content: system },
109	          { role: "user", content: prompt },
110	        ],
111	        temperature: 0,
112	      }),
113	      signal,
114	    },
115	  );
116	  if (!res.ok) {
117	    const body = await res.text();
118	    throw new Error(`Bifrost ${res.status}: ${body.slice(0, 300)}`);
119	  }
120	  const json = (await res.json()) as {
121	    choices?: Array<{ message?: { content?: string } }>;
122	  };
123	  const raw = json.choices?.[0]?.message?.content ?? "";
124	  let label = "";
125	  let explanation = "";
126	  let txt = raw.trim();
127	  if (txt.startsWith("```")) {
128	    txt = txt
129	      .replace(/^```[a-z]*\n?/, "")
130	      .replace(/```$/, "")
131	      .trim();
132	  }
133	  try {
134	    const obj = JSON.parse(txt) as { label?: string; explanation?: string };
135	    label = String(obj.label ?? "")
136	      .trim()
137	      .toLowerCase();
138	    explanation = String(obj.explanation ?? "").trim();
139	  } catch {
140	    const low = raw.toLowerCase();
141	    label = labels.find((l) => low.includes(l)) ?? "?";
142	    explanation = raw.trim().slice(0, 200);
143	  }
144	  if (!(label in valid)) {
145	    label = labels.find((l) => label.includes(l)) ?? "?";
146	  }
147	  return { label, score: label in valid ? valid[label] : null, explanation };
148	}
149	
150	function readDataset(): Map<string, DatasetRow> {
151	  const raw = readFileSync(DATASET_PATH, "utf8").trim();
152	  const map = new Map<string, DatasetRow>();
153	  for (const line of raw.split(/\n+/).filter(Boolean)) {
154	    const row = JSON.parse(line) as DatasetRow;
155	    map.set(row.case_id, row);
156	  }
157	  return map;
158	}
159	
160	async function main(): Promise<void> {
161	  const dataset = readDataset();
162	  const runs = JSON.parse(readFileSync(RUNS_PATH, "utf8")) as RunOutput[];
163	  console.log(`[twyne:judge] ${runs.length} runs → judge ${JUDGE_MODEL}`);
164	
165	  const scores: CaseScore[] = [];
166	  let failures = 0;
167	  for (const run of runs) {
168	    const row = dataset.get(run.case_id);
169	    if (!row) {
170	      console.error(`  ✗ ${run.case_id}: no dataset row`);
171	      failures += 1;
172	      continue;
173	    }
174	    if (run.output.startsWith("[error]")) {
175	      console.error(`  ✗ ${run.case_id}: generation errored, skipping judge`);
176	      failures += 1;
177	      continue;
178	    }
179	    try {
180	      const faithfulness = await judge(
181	        FAITHFULNESS_TEMPLATE(row.draftText, run.output),
182	        CHOICES.faithfulness,
183	        AbortSignal.timeout(90_000),
184	      );
185	      const helpfulness = await judge(
186	        HELPFULNESS_TEMPLATE(row.persona, row.draftText, run.output),
187	        CHOICES.helpfulness,
188	        AbortSignal.timeout(90_000),
189	      );
190	      scores.push({
191	        case_id: run.case_id,
192	        persona: row.persona,
193	        faithfulness,
194	        helpfulness,
195	      });
196	      console.log(
197	        `  ${run.case_id.padEnd(22)} faithful=${faithfulness.label.padEnd(9)}(${faithfulness.score})  helpful=${helpfulness.label.padEnd(5)}(${helpfulness.score})`,
198	      );
199	    } catch (err) {
200	      failures += 1;
201	      console.error(`  ✗ ${run.case_id}: ${(err as Error).message}`);
202	    }
203	  }
204	
205	  writeFileSync(SCORES_PATH, JSON.stringify(scores, null, 2));
206	  const fok = scores.filter((s) => s.faithfulness.score === 1).length;
207	  const hok = scores.filter((s) => s.helpfulness.score === 1).length;
208	  console.log(
209	    `[twyne:judge] wrote ${scores.length} scores to evals/scores.json` +

