1	/**
2	 * Background agents — the Apparatus runs in the background, watching the
3	 * draft and surfacing sources without the writer having to ask. The model
4	 * is intentionally simple:
5	 *
6	 *   1. Watch the active folio for content changes (debounced, 45s).
7	 *   2. Derive a research query from the brief + the current draft.
8	 *   3. Skip the call if the same query was run recently (cache).
9	 *   4. Call the search provider, merge the top results into the bibliography
10	 *      with `provenance: "background"` so the panel can tell who found them.
11	 *   5. Emit `twyne:background-research` so the UI can show what is happening.
12	 *
13	 * The Convex client and a brief are required. When the client is absent
14	 * (offline) the watcher is a no-op — the writer will still see their
15	 * manually-saved sources.
16	 */
17	
18	import type { ConvexClient } from "convex/browser";
19	import { api } from "../../convex/_generated/api";
20	import type { Source } from "../../convex/research";
21	import type { ProjectBrief } from "../types";
22	import {
23	  type BibEntry,
24	  loadBibliography,
25	  saveBibliography,
26	  normalizeUrl,
27	} from "./bibliography";
28	
29	const DEBOUNCE_MS = 45_000;
30	const QUERY_CACHE_TTL_MS = 5 * 60_000; // re-run same query at most every 5m
31	const MAX_BACKGROUND_PER_FOLIO = 25; // soft cap so the bib doesn't grow forever
32	const SNIPPET_MIN_CHARS = 60; // skip throwaway stubs
33	
34	interface ResearchState {
35	  lastQuery: string;
36	  lastQueryAt: number;
37	  /** Total background saves this session. */
38	  savedThisSession: number;
39	  /** Last "now researching" indicator. */
40	  lastTickAt: number;
41	  lastStatus: "idle" | "running" | "saving" | "error";
42	  lastError?: string;
43	}
44	
45	const state: ResearchState = {
46	  lastQuery: "",
47	  lastQueryAt: 0,
48	  savedThisSession: 0,
49	  lastTickAt: 0,
50	  lastStatus: "idle",
51	};
52	
53	let debounceTimer: ReturnType<typeof setTimeout> | null = null;
54	let activeClient: ConvexClient | null = null;
55	let activeBrief: ProjectBrief | null = null;
56	let activeFolioId: string | null = null;
57	
58	function setStatus(
59	  status: ResearchState["lastStatus"],
60	  error?: string,
61	): void {
62	  state.lastStatus = status;
63	  state.lastTickAt = Date.now();
64	  if (error) state.lastError = error;
65	  notify();
66	}
67	
68	function notify(): void {
69	  if (typeof window === "undefined") return;
70	  window.dispatchEvent(
71	    new CustomEvent("twyne:background-research", { detail: snapshot() }),
72	  );
73	}
74	
75	export function snapshot() {
76	  return {
77	    lastQuery: state.lastQuery,
78	    lastQueryAt: state.lastQueryAt,
79	    savedThisSession: state.savedThisSession,
80	    lastTickAt: state.lastTickAt,
81	    status: state.lastStatus,
82	    error: state.lastError,
83	    activeFolioId,
84	  };
85	}
86	
87	/** Derive a research query from the brief + current draft. */
88	export function deriveQuery(
89	  brief: ProjectBrief | null,
90	  draftText: string,
91	): string {
92	  const a = brief?.answers;
93	  const fragments: string[] = [];
94	  if (a?.workingTitle) fragments.push(a.workingTitle);
95	  if (a?.audience) fragments.push(`for ${a.audience}`);
96	  if (a?.goal) fragments.push(a.goal);
97	  if (a?.tone) fragments.push(`tone: ${a.tone}`);
98	  if (a?.format) fragments.push(`format: ${a.format}`);
99	  const trimmed = draftText.trim().slice(0, 280);
100	  if (trimmed) fragments.push(trimmed);
101	  return fragments.join(" · ").trim();
102	}
103	
104	/** Hash a query to dedupe. */
105	function hashQuery(q: string): string {
106	  // Cheap FNV-1a — we don't need crypto, just stable identity.
107	  let h = 0x811c9dc5;
108	  for (let i = 0; i < q.length; i++) {
109	    h ^= q.charCodeAt(i);
110	    h = Math.imul(h, 0x01000193);
111	  }
112	  return (h >>> 0).toString(36);
113	}
114	
115	function sameAsRecent(q: string): boolean {
116	  return (
117	    hashQuery(q) === hashQuery(state.lastQuery) &&
118	    Date.now() - state.lastQueryAt < QUERY_CACHE_TTL_MS
119	  );
120	}
121	
122	/** Stop any pending or running work. */
123	export function stopBackgroundResearch(): void {
124	  if (debounceTimer) {
125	    clearTimeout(debounceTimer);
126	    debounceTimer = null;
127	  }
128	  setStatus("idle");
129	}
130	
131	/** Configure the research watcher. Safe to call repeatedly — the latest
132	 *  args win. */
133	export function startBackgroundResearch(args: {
134	  client: ConvexClient | null;
135	  brief: ProjectBrief | null;
136	  folioId: string | null;
137	}): void {
138	  activeClient = args.client;
139	  activeBrief = args.brief;
140	  activeFolioId = args.folioId;
141	  // No client = no remote research; mark idle but still emit a tick so
142	  // the UI knows we're listening.
143	  setStatus(activeClient ? "idle" : "idle");
144	}
145	
146	/** Re-run research now (used on folio switch and on initial load). */
147	export function kickBackgroundResearch(draftText: string): void {
148	  if (!activeClient) return;
149	  if (!activeFolioId) return;
150	  schedule(draftText, 0);
151	}
