1	/**
2	 * Offline rubric eval for Twyne.
3	 *
4	 * Replays the REAL production prompts from `convex/agentPrompts.ts` through the
5	 * Bifrost gateway for two task types, then scores the outputs with LLM-as-judge
6	 * rubrics. Mirrors the conventions of `evals/run-experiment.ts` and
7	 * `evals/judge.ts` (Node/TS via `tsx`, `node:fs`/`node:path` imports,
8	 * header-only Bifrost auth, case_id keys, main().catch() tail).
9	 *
10	 * Tasks:
11	 *   - rubric-judge   : production `judgeDraft` task. Generates a persona-scored
12	 *                      {score, rationale} using buildSystemPrompt +
13	 *                      buildUserPrompt + the verbatim JUDGE TASK suffix from
14	 *                      convex/agents.ts. Scores structural validity and
15	 *                      rationale-groundedness, then checks discrimination on
16	 *                      strong/weak pairs.
17	 *   - rubric-review  : production `buildRubricReviewPrompt` task. Generates the
18	 *                      Chief Critic narrative review given a pre-computed
19	 *                      grade and judges' verdicts. Scores whether the review
20	 *                      honours the given grade and closes with a revision plan.
21	 *
22	 * Usage:
23	 *   BIFROST_BASE_URL=https://... BIFROST_API_KEY=sk_bf_xxx \
24	 *     JUDGE_MODEL=neuralwatt/kimi-k2.6 bun run eval:rubric
25	 *
26	 * Writes evals/rubric-scores.json.
27	 */
28	import { readFileSync, writeFileSync } from "node:fs";
29	import { dirname, resolve } from "node:path";
30	import { fileURLToPath } from "node:url";
31	
32	import {
33	  buildRubricReviewPrompt,
34	  buildRubricReviewSystemPrompt,
35	  buildSystemPrompt,
36	  buildUserPrompt,
37	  toAgentPersona,
38	  type AgentPersona,
39	  type AgentRequest,
40	} from "../convex/agentPrompts";
41	import { PERSONAS } from "../src/utils/personas";
42	
43	const HERE = dirname(fileURLToPath(import.meta.url));
44	const DATASET_PATH = resolve(HERE, "rubric.jsonl");
45	const SCORES_PATH = resolve(HERE, "rubric-scores.json");
46	
47	const BIFROST_BASE_URL = process.env.BIFROST_BASE_URL;
48	const BIFROST_API_KEY = process.env.BIFROST_API_KEY;
49	const JUDGE_MODEL = process.env.JUDGE_MODEL ?? "neuralwatt/kimi-k2.6";
50	
51	/**
52	 * The JUDGE TASK suffix appended to the user prompt by `judgeDraft` in
53	 * `convex/agents.ts`. Copied verbatim — the production rubric depends on this
54	 * exact wording and the JSON shape. If you change it here, also change it
55	 * there.
56	 */
57	const JUDGE_TASK_SUFFIX = (personaName: string): string =>
58	  `
59	JUDGE TASK: As ${personaName}, give the draft a single integer score from 1 to 10. A score of 5 means "the draft is doing the work for the stated audience and goal but has clear, fixable issues." A score of 7 means "the draft is in good shape and the issues are minor." A score of 9 means "publishable as-is." Be honest; most first drafts are in the 3-5 range.
60	
61	Do not reward confident-sounding bullshit. Penalize generic filler, repeated paragraphs, unsupported universal claims, vibes without evidence, fake specificity, and any passage that sounds polished while dodging the stated audience/goal.
62	
63	Respond as JSON, and only JSON, in this exact shape:
64	{"score": <integer 1-10>, "rationale": "<one sentence, your voice>"}`;
65	
66	interface JudgeVerdict {
67	  personaId: string;
68	  score: number;
69	  rationale: string;
70	}
71	
72	interface RubricJudgeRow {
73	  case_id: string;
74	  task: "rubric-judge";
75	  persona: string;
76	  /** "strong" | "weak" — used by the discrimination check after scoring. */
77	  draftQuality?: "strong" | "weak";
78	  draftText: string;
79	}
80	
81	interface RubricReviewRow {
82	  case_id: string;
83	  task: "rubric-review";
84	  combined: number;
85	  grade: string;
86	  judgeMean: number;
87	  staticTotal: number;
88	  judges: JudgeVerdict[];
89	  staticFeedback: string[];
90	  draftText: string;
91	}
92	
93	type DatasetRow = RubricJudgeRow | RubricReviewRow;
94	
95	interface LlmVerdict {
96	  label: string;
97	  score: number | null;
98	  explanation: string;
99	}
100	
101	interface JudgeOutput {
102	  raw: string;
103	  score: number | null;
104	  rationale: string | null;
105	  /** Score landed in [1,10] as an integer. */
106	  score_in_range: boolean;
107	}
108	
109	interface JudgeScore {
110	  case_id: string;
111	  task: "rubric-judge";
112	  persona: string;
113	  draft_quality: string | null;
114	  output_excerpt: string;
115	  judge: JudgeOutput;
116	  grounded: LlmVerdict;
117	}
118	
119	interface ReviewScore {
120	  case_id: string;
121	  task: "rubric-review";
122	  output_excerpt: string;
123	  faithful_to_grade: LlmVerdict;
124	  has_revision_plan: LlmVerdict;
125	}
126	
127	type RubricScore = JudgeScore | ReviewScore;
128	
129	interface DiscriminationPair {
130	  persona: string;
131	  strong_case_id: string;
132	  weak_case_id: string;
133	  strong_score: number | null;
134	  weak_score: number | null;
135	  passed: boolean;
136	}
137	
138	const RATIONALE_GROUNDED_TEMPLATE = (
139	  draft: string,
140	  rationale: string,
141	): string =>
142	  `You judge whether a judge's one-sentence rationale genuinely engages with the SPECIFIC draft it was scoring, versus generic writing advice that could apply to any text.\n\n` +
143	  `Draft:\n${draft}\n\nRationale:\n${rationale}\n\n` +
144	  `Answer "grounded" if the rationale references specific content, claims, or wording from THIS draft. Answer "generic" if it is boilerplate that could apply to any text.`;
145	
146	const FAITHFUL_TO_GRADE_TEMPLATE = (
147	  grade: string,
148	  combined: number,
149	  judgeMean: number,
150	  staticTotal: number,
151	  review: string,
152	): string =>
153	  `You judge whether an AI Chief Critic's narrative review respects the GIVEN grade and numeric scores.\n\n` +
154	  `GIVEN (do not let the review contradict these):\n- combined: ${combined}/100\n- grade: ${grade}\n- judge mean: ${judgeMean.toFixed(1)}/10\n- static features: ${staticTotal.toFixed(1)}/10\n\n` +
155	  `REVIEW:\n${review}\n\n` +
156	  `Answer "faithful" if the review interprets the given numbers, walks through what the grade means, and does NOT invent new numeric scores of its own (e.g. its own X/10 or Y%). ` +
157	  `Answer "invented" if the review contradicts the given grade/scores OR coins new numeric scores that were not supplied.`;
158	
159	const REVISION_PLAN_TEMPLATE = (review: string): string =>
160	  `You judge whether an AI Chief Critic's narrative review closes with a concrete, prioritised revision plan.\n\n` +
161	  `REVIEW:\n${review}\n\n` +
162	  `Answer "present" if the final section of the review lists multiple (>=2) concrete, specific revision steps the writer can take, ordered by priority. ` +
163	  `Answer "absent" if the review ends on a general exhortation, a vague suggestion, or no actionable plan at all.`;
164	
165	const CHOICES = {
166	  grounded: { grounded: 1, generic: 0 },
167	  faithful: { faithful: 1, invented: 0 },
168	  plan: { present: 1, absent: 0 },
169	} as const;
170	
171	function personaOrThrow(id: string): AgentPersona {
172	  const p = PERSONAS.find((x) => x.id === id);
173	  if (!p) {
174	    throw new Error(
175	      `Unknown persona id "${id}" — add it to src/utils/personas.ts`,
176	    );
177	  }
178	  return toAgentPersona(p);
179	}
180	
181	function readDataset(): DatasetRow[] {
182	  const raw = readFileSync(DATASET_PATH, "utf8").trim();
183	  return raw
184	    .split(/\n+/)
185	    .filter(Boolean)
186	    .map((line, i) => {
187	      try {
188	        return JSON.parse(line) as DatasetRow;
189	      } catch (err) {
190	        throw new Error(`Bad JSONL line ${i + 1}: ${(err as Error).message}`);
191	      }
192	    });
193	}
194	
195	async function callBifrost(
196	  system: string,
197	  user: string,
198	  model: string,
199	  temperature: number,
200	  signal: AbortSignal,
201	  maxOutputTokens: number | null = null,
202	): Promise<string> {
203	  if (!BIFROST_BASE_URL) {
204	    throw new Error("BIFROST_BASE_URL is required");
205	  }
206	  const body: Record<string, unknown> = {
207	    model,
208	    messages: [
209	      { role: "system", content: system },
210	      { role: "user", content: user },
211	    ],
212	    temperature,
213	  };
214	  if (maxOutputTokens !== null) body.max_tokens = maxOutputTokens;
215	  const res = await fetch(
216	    `${BIFROST_BASE_URL.replace(/\/$/, "")}/chat/completions`,
217	    {
218	      method: "POST",
219	      // Header-only auth: Bifrost passes its stored provider key through. A
220	      // bearer token would be misread as a virtual-key lookup → 401. This is
221	      // exactly why the Arize integration's auth_type must be proxy_with_headers.
222	      headers: {
223	        "content-type": "application/json",
224	        "x-bifrost-api-key": BIFROST_API_KEY ?? "",
225	      },
226	      body: JSON.stringify(body),
227	      signal,
228	    },
229	  );
230	  if (!res.ok) {
231	    const body = await res.text();
232	    throw new Error(`Bifrost ${res.status}: ${body.slice(0, 300)}`);
233	  }
234	  const json = (await res.json()) as {
235	    choices?: Array<{ message?: { content?: string } }>;
236	  };
237	  const content = json.choices?.[0]?.message?.content;
238	  if (typeof content !== "string") {
239	    throw new Error("Bifrost response missing choices[0].message.content");
240	  }
241	  return content;
242	}
243	
244	/** Strip ```json / ``` fences the way `parseJudgeOutput` does in agents.ts. */
245	function stripFences(text: string): string {
246	  return text
247	    .replace(/```(?:json)?/gi, "")
248	    .replace(/```/g, "")
249	    .trim();
250	}
251	
252	/** Extract the first {...} JSON object from a possibly-padded string. */
253	function extractFirstJsonObject(text: string): string | null {
254	  const start = text.indexOf("{");
255	  const end = text.lastIndexOf("}");
256	  if (start === -1 || end === -1 || end <= start) return null;
257	  return text.slice(start, end + 1);
258	}
259	
260	function parseScoreRationale(raw: string): {
261	  score: number | null;
262	  rationale: string | null;
263	} {
264	  const stripped = stripFences(raw);
265	  const candidate = extractFirstJsonObject(stripped) ?? stripped;
266	  // Strict first.
267	  try {
268	    const obj = JSON.parse(candidate) as {
269	      score?: unknown;
270	      rationale?: unknown;
271	    };
272	    if (typeof obj.score === "number" && typeof obj.rationale === "string") {
273	      return { score: clampScore(obj.score), rationale: obj.rationale };
274	    }
275	  } catch {
276	    // fall through to the looser parse
277	  }
278	  // Looser fallback, mirroring parseJudgeOutput in agents.ts.
279	  const scoreMatch = candidate.match(/"?score"?\s*[:=]\s*(\d+)/i);
280	  const rationaleMatch = candidate.match(/"?rationale"?\s*[:=]\s*"([^"]+)"/i);
281	  if (scoreMatch) {
282	    return {
283	      score: clampScore(parseInt(scoreMatch[1], 10)),
284	      rationale:
285	        rationaleMatch?.[1] ??
286	        "The draft does part of the work and leaves the rest to the writer.",
287	    };
288	  }
289	  return { score: null, rationale: null };
290	}
291	
292	function clampScore(score: number): number {
293	  if (!Number.isFinite(score)) return 5;
294	  return Math.max(1, Math.min(10, Math.round(score)));
295	}
296	
297	function clampIntInRange(score: number): boolean {
298	  return Number.isInteger(score) && score >= 1 && score <= 10;
299	}
300	
301	async function judgeLabel(
302	  prompt: string,
303	  valid: Record<string, number>,
304	  signal: AbortSignal,
305	): Promise<LlmVerdict> {
306	  const labels = Object.keys(valid);
307	  const system =
308	    `You are a strict evaluator. Read the rubric, then respond with a JSON object ` +
309	    `exactly: {"label": "<one of: ${labels.join(", ")}>", "explanation": "<one sentence>"}. ` +
310	    `No other text.`;
311	  const raw = await callBifrost(system, prompt, JUDGE_MODEL, 0, signal);
312	  let label = "";
313	  let explanation = "";
314	  const txt = stripFences(raw);
315	  try {
316	    const obj = JSON.parse(extractFirstJsonObject(txt) ?? txt) as {
317	      label?: string;
318	      explanation?: string;
319	    };
320	    label = String(obj.label ?? "")
321	      .trim()
322	      .toLowerCase();
323	    explanation = String(obj.explanation ?? "").trim();
324	  } catch {
325	    const low = raw.toLowerCase();
326	    label = labels.find((l) => low.includes(l)) ?? "?";
327	    explanation = raw.trim().slice(0, 200);
328	  }
329	  if (!(label in valid)) {
330	    label = labels.find((l) => label.includes(l)) ?? "?";
331	  }
332	  return {
333	    label,
334	    score: label in valid ? valid[label] : null,
335	    explanation,
336	  };
337	}
338	
339	function excerpt(text: string, max = 160): string {
340	  const oneLine = text.replace(/\s+/g, " ").trim();
341	  return oneLine.length <= max ? oneLine : `${oneLine.slice(0, max)}…`;
342	}
343	
344	async function scoreRubricJudgeRow(row: RubricJudgeRow): Promise<JudgeScore> {
345	  const persona = personaOrThrow(row.persona);
346	  const req: AgentRequest = {
347	    persona,
348	    brief: null,
349	    draftText: row.draftText,
350	    instruction: "feedback",
351	  };
352	  const system = buildSystemPrompt(persona);
353	  const user = buildUserPrompt(req) + JUDGE_TASK_SUFFIX(persona.name);
354	
355	  const raw = await callBifrost(
356	    system,
357	    user,
358	    JUDGE_MODEL,
359	    0.2,
360	    AbortSignal.timeout(90_000),
361	    220,
362	  );
363	  const parsed = parseScoreRationale(raw);
364	  const judgeOutput: JudgeOutput = {
365	    raw: excerpt(raw),
366	    score: parsed.score,
367	    rationale: parsed.rationale,
368	    score_in_range: parsed.score !== null && clampIntInRange(parsed.score),
369	  };
370	
371	  let grounded: LlmVerdict;
372	  if (parsed.rationale) {
373	    grounded = await judgeLabel(
374	      RATIONALE_GROUNDED_TEMPLATE(row.draftText, parsed.rationale),
375	      CHOICES.grounded,
376	      AbortSignal.timeout(90_000),
377	    );
378	  } else {
379	    grounded = {
380	      label: "?",
381	      score: null,
382	      explanation: "no rationale parsed from judge output",
383	    };
384	  }
385	
386	  return {
387	    case_id: row.case_id,
388	    task: "rubric-judge",
389	    persona: row.persona,
390	    draft_quality: row.draftQuality ?? null,
391	    output_excerpt: excerpt(raw),
392	    judge: judgeOutput,
393	    grounded,
394	  };
395	}
396	
397	async function scoreRubricReviewRow(
398	  row: RubricReviewRow,
399	): Promise<ReviewScore> {
400	  const system = buildRubricReviewSystemPrompt();
401	  const user = buildRubricReviewPrompt({
402	    combined: row.combined,
403	    grade: row.grade,
404	    judgeMean: row.judgeMean,
405	    staticTotal: row.staticTotal,
406	    judges: row.judges,
407	    staticFeedback: row.staticFeedback,
408	    brief: null,
409	    draftText: row.draftText,
410	  });
411	
412	  const raw = await callBifrost(
413	    system,
414	    user,
415	    JUDGE_MODEL,
416	    0.4,
417	    AbortSignal.timeout(120_000),
418	    1400,
419	  );
420	  const faithful = await judgeLabel(
421	    FAITHFUL_TO_GRADE_TEMPLATE(
422	      row.grade,
423	      row.combined,
424	      row.judgeMean,
425	      row.staticTotal,
426	      raw,
427	    ),
428	    CHOICES.faithful,
429	    AbortSignal.timeout(90_000),
430	  );
431	  const plan = await judgeLabel(
432	    REVISION_PLAN_TEMPLATE(raw),
433	    CHOICES.plan,
434	    AbortSignal.timeout(90_000),
435	  );
436	
437	  return {
438	    case_id: row.case_id,
439	    task: "rubric-review",
440	    output_excerpt: excerpt(raw),
441	    faithful_to_grade: faithful,
442	    has_revision_plan: plan,
443	  };
444	}
445	
446	function buildDiscriminationPairs(
447	  rows: RubricJudgeRow[],
448	): DiscriminationPair[] {
449	  const byQuality = new Map<
450	    string,
451	    { strong?: RubricJudgeRow; weak?: RubricJudgeRow }
452	  >();
453	  for (const r of rows) {
454	    const q = r.draftQuality;
455	    if (!q) continue;
456	    const slot = byQuality.get(r.persona) ?? {};
457	    slot[q] = r;
458	    byQuality.set(r.persona, slot);
459	  }
460	  const pairs: DiscriminationPair[] = [];
461	  for (const [persona, slot] of byQuality) {
462	    if (!slot.strong || !slot.weak) continue;
463	    pairs.push({
464	      persona,
465	      strong_case_id: slot.strong.case_id,
466	      weak_case_id: slot.weak.case_id,
467	      strong_score: null,
468	      weak_score: null,
469	      passed: false,
470	    });
471	  }
472	  return pairs;
473	}
474	
475	async function main(): Promise<void> {
476	  const dataset = readDataset();
477	  console.log(`[twyne:rubric] ${dataset.length} cases → judge ${JUDGE_MODEL}`);
478	
479	  const scores: RubricScore[] = [];
480	  let failures = 0;
481	  const judgeRows: RubricJudgeRow[] = [];
482	
483	  for (const row of dataset) {
484	    try {
485	      if (row.task === "rubric-judge") {
486	        judgeRows.push(row);
487	        const s = await scoreRubricJudgeRow(row);
488	        scores.push(s);
489	        console.log(
490	          `  ${row.case_id.padEnd(24)} (${row.persona.padEnd(8)}) score=${String(s.judge.score).padStart(3)} range=${String(s.judge.score_in_range).padEnd(5)} grounded=${s.grounded.label}`,
491	        );
492	      } else {
493	        const s = await scoreRubricReviewRow(row);
494	        scores.push(s);
495	        console.log(
496	          `  ${row.case_id.padEnd(24)} faithful=${s.faithful_to_grade.label.padEnd(9)} plan=${s.has_revision_plan.label}`,
497	        );
498	      }
499	    } catch (err) {
500	      failures += 1;
501	      const message = (err as Error).message;
502	      console.error(`  ✗ ${row.case_id}: ${message}`);
503	      // Mirror run-experiment.ts: record a placeholder so the artifact is
504	      // complete and downstream tooling can see which rows errored.
505	      if (row.task === "rubric-judge") {
506	        scores.push({
507	          case_id: row.case_id,
508	          task: "rubric-judge",
509	          persona: row.persona,
510	          draft_quality: row.draftQuality ?? null,
511	          output_excerpt: `[error] ${excerpt(message)}`,
512	          judge: {
513	            raw: `[error] ${excerpt(message)}`,
514	            score: null,
515	            rationale: null,
516	            score_in_range: false,
517	          },
518	          grounded: { label: "?", score: null, explanation: message },
519	        });
520	      } else {
521	        scores.push({
522	          case_id: row.case_id,
523	          task: "rubric-review",
524	          output_excerpt: `[error] ${excerpt(message)}`,
525	          faithful_to_grade: { label: "?", score: null, explanation: message },
526	          has_revision_plan: { label: "?", score: null, explanation: message },
527	        });
528	      }
529	    }
530	  }
531	
532	  // Discrimination: for each persona with both strong + weak, assert strong > weak.
533	  const pairs = buildDiscriminationPairs(judgeRows);
534	  for (const pair of pairs) {
535	    const strong = scores.find(
536	      (s) =>
537	        s.task === "rubric-judge" &&
538	        (s as JudgeScore).case_id === pair.strong_case_id,
539	    ) as JudgeScore | undefined;
540	    const weak = scores.find(
541	      (s) =>
542	        s.task === "rubric-judge" &&
543	        (s as JudgeScore).case_id === pair.weak_case_id,
544	    ) as JudgeScore | undefined;
545	    if (strong?.judge.score != null && weak?.judge.score != null) {
546	      pair.strong_score = strong.judge.score;
547	      pair.weak_score = weak.judge.score;
548	      pair.passed = pair.strong_score > pair.weak_score;
549	    }
550	  }
551	
552	  writeFileSync(
553	    SCORES_PATH,
554	    JSON.stringify({ scores, discrimination_pairs: pairs }, null, 2),
555	  );
556	
557	  // Summary.
558	  const judgeScores = scores.filter(
559	    (s): s is JudgeScore => s.task === "rubric-judge",
560	  );
561	  const reviewScores = scores.filter(
562	    (s): s is ReviewScore => s.task === "rubric-review",
563	  );
564	  const inRange = judgeScores.filter((s) => s.judge.score_in_range).length;
565	  const grounded = judgeScores.filter((s) => s.grounded.score === 1).length;
566	  const faithful = reviewScores.filter(
567	    (s) => s.faithful_to_grade.score === 1,
568	  ).length;
569	  const planned = reviewScores.filter(
570	    (s) => s.has_revision_plan.score === 1,
571	  ).length;
572	  const pairsPassed = pairs.filter((p) => p.passed).length;
573	
574	  console.log(
575	    `[twyne:rubric] wrote ${scores.length} rows to evals/rubric-scores.json`,
576	  );
577	  console.log(
578	    `  rubric-judge:    score_in_range ${inRange}/${judgeScores.length}, ` +
579	      `rationale grounded ${grounded}/${judgeScores.length}`,
580	  );
581	  console.log(
582	    `  rubric-review:   faithful-to-grade ${faithful}/${reviewScores.length}, ` +
583	      `has-revision-plan ${planned}/${reviewScores.length}`,
584	  );
585	  console.log(
586	    `  discrimination:  ${pairsPassed}/${pairs.length} strong>weak pairs`,
587	  );
588	  for (const p of pairs) {
589	    const mark = p.passed ? "PASS" : "FAIL";
590	    console.log(
591	      `    [${mark}] ${p.persona}: strong=${p.strong_score} > weak=${p.weak_score} ` +
592	        `(${p.strong_case_id} vs ${p.weak_case_id})`,
593	    );
594	  }
595	
596	  if (failures > 0) {
597	    process.exitCode = 1;
598	  }
599	}
600	
601	main().catch((err) => {
602	  console.error("[twyne:rubric] fatal:", err);
603	  process.exit(1);
604	});
605

